  QueryBuilder<JournalEntry, String, QQueryOperations> moodProperty() {
    return QueryBuilder.apply(this, (query) {
      return query.addPropertyName(r'mood');
    });
  }

  QueryBuilder<JournalEntry, String, QQueryOperations> textProperty() {
